code_example_1.code:
/ Base Styles (Mobile
First) /
.container {
 display: flex;
 flex-direction: column;

padding: 20px;
}

.box {
 background: lightblue;
 margin-bottom: 10px;

height: 100px;
}

/ Tablet/Desktop Styles /
@media (min-width: 768px) {

.container {
 flex-direction: row;
 gap: 20px;
 }
 .box {
 flex: 1;

margin-bottom: 0;
 }
}

code_example_2.code:
/ Text that scales between 24px and 48px /
.title {
 font-size:
clamp(1.5rem, 4vw + 1rem, 3rem);
 text-align: center;
}

/ Image that never
overflows its parent */
.hero-img {
 max-width: 100%;
 height: auto;

display: block;
}

questions_and_answers.answer:
.grid-container {
 display: grid;

grid-template-columns: 1fr;
 gap: 10px;
}

@media (min-width: 768px) {

.grid-container {
 grid-template-columns: repeat(2, 1fr);
 }
}

@media
(min-width: 1024px) {
 .grid-container {
 grid-template-columns:
repeat(4, 1fr);
 }
}
